import React, { useState, useCallback, useMemo } from 'react';
import { createPortal } from 'react-dom';
import type { BankStatementDryRunResult, BankStatementDryRunRow, CustomerResolution, BatchDetailLine } from '../../../../../services/kt/bankStatementImportModels';
import CustomerResolveModal from '../CustomerResolveModal/CustomerResolveModal';
import BatchRefConfigModal from '../BatchRefConfigModal/BatchRefConfigModal';
import ExpenseAssignmentModal from './ExpenseAssignmentModal';
import styles from './Step2DryRun.module.css';

interface Step2DryRunProps {
  dryRunResult: BankStatementDryRunResult;
  resolutions: CustomerResolution[];
  onResolutionsChange: (resolutions: CustomerResolution[]) => void;
  onNext: () => void;
  onBack: () => void;
  /** Batch detail lines per batch ref (từ file thanh toán lô). */
  batchDetailMap?: Map<string, BatchDetailLine[]>;
}

interface BatchRefConfigState {
  row: BankStatementDryRunRow;
  currentSelectedRef?: string;
  currentIsBatch?: boolean;
  currentReason?: string;
}

const STATUS_LABEL: Record<string, { text: string; className: string }> = {
  ok: { text: 'Sẵn sàng', className: 'statusOk' },
  missing_customer: { text: 'Thiếu KH', className: 'statusMissing' },
  error: { text: 'Lỗi', className: 'statusError' },
};

const Step2DryRun: React.FC<Step2DryRunProps> = ({ dryRunResult, resolutions, onResolutionsChange, onNext, onBack, batchDetailMap }) => {
  const [resolveRow, setResolveRow] = useState<BankStatementDryRunRow | null>(null);
  const [batchRefRow, setBatchRefRow] = useState<BatchRefConfigState | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [detailRow, setDetailRow] = useState<BankStatementDryRunRow | null>(null);
  const [expenseRow, setExpenseRow] = useState<BankStatementDryRunRow | null>(null);
  const [showBatchDetailOnly, setShowBatchDetailOnly] = useState(false);

  const getResolution = useCallback(
    (rowIndex: number) => resolutions.find(r => r.rowIndex === rowIndex),
    [resolutions]
  );

  // ── Batch detail: compute lines for matched batch ref ──────
  const getBatchDetailLines = useCallback((row: BankStatementDryRunRow): BatchDetailLine[] => {
    if (!batchDetailMap || !row.matchedBatchRefs?.length) return [];
    const lines: BatchDetailLine[] = [];
    for (const ref of row.matchedBatchRefs) {
      const refLines = batchDetailMap.get(ref) || batchDetailMap.get(row.description || '');
      if (refLines) lines.push(...refLines);
    }
    return lines;
  }, [batchDetailMap]);

  // ── Customer resolve ───────────────────────────────────────
  const handleResolveSave = useCallback((resolution: CustomerResolution) => {
    const idx = resolutions.findIndex(r => r.rowIndex === resolution.rowIndex);
    const next = [...resolutions];

    const currentRow = dryRunResult.rows.find(r => r.rowIndex === resolution.rowIndex);
    if (currentRow?.counterpartyName) {
      const sameCounterpartyRows = dryRunResult.rows
        .filter(r =>
          r.rowIndex !== resolution.rowIndex &&
          r.status === 'missing_customer' &&
          r.counterpartyName &&
          r.counterpartyName.toLowerCase() === currentRow.counterpartyName!.toLowerCase()
        )
        .map(r => r.rowIndex);

      if (sameCounterpartyRows.length > 0) {
        resolution.autoApplyRowIndices = sameCounterpartyRows;
        for (const autoIdx of sameCounterpartyRows) {
          const existing = resolutions.find(r => r.rowIndex === autoIdx);
          if (!existing) {
            next.push({
              rowIndex: autoIdx,
              existingCustomerId: resolution.existingCustomerId,
              newCustomer: resolution.newCustomer ? { ...resolution.newCustomer, name: dryRunResult.rows.find(r => r.rowIndex === autoIdx)?.counterpartyName || resolution.newCustomer.name } : undefined,
            });
          }
        }
      }
    }

    if (idx >= 0) next[idx] = resolution;
    else next.push(resolution);

    onResolutionsChange(next);
    setResolveRow(null);
  }, [resolutions, onResolutionsChange, dryRunResult.rows]);

  // ── Batch ref config handler ───────────────────────────────
  const handleBatchRefSave = useCallback((
    rowIndex: number,
    selectedBatchRef: string | undefined,
    isBatchTransaction: boolean,
    batchConfirmReason: string,
  ) => {
    const idx = resolutions.findIndex(r => r.rowIndex === rowIndex);
    const next = [...resolutions];

    const existing = idx >= 0 ? next[idx] : { rowIndex };

    const updated: CustomerResolution = {
      ...existing,
      selectedBatchRef,
      batchConfirmReason: isBatchTransaction && selectedBatchRef ? batchConfirmReason : undefined,
    };

    if (idx >= 0) next[idx] = updated;
    else next.push(updated);

    onResolutionsChange(next);
    setBatchRefRow(null);
  }, [resolutions, onResolutionsChange]);

  // ── Skip / Expense handlers ────────────────────────────────
  const handleToggleSkip = useCallback((rowIndex: number) => {
    const idx = resolutions.findIndex(r => r.rowIndex === rowIndex);
    const next = [...resolutions];
    const existing = idx >= 0 ? { ...next[idx] } : { rowIndex };

    existing.skipOnImport = !existing.skipOnImport;
    if (idx >= 0) next[idx] = existing;
    else next.push(existing);

    onResolutionsChange(next);
  }, [resolutions, onResolutionsChange]);

  const handleExpenseSave = useCallback((rowIndex: number, storeCode: string | null, storeName: string, isCommon: boolean) => {
    const idx = resolutions.findIndex(r => r.rowIndex === rowIndex);
    const next = [...resolutions];
    const existing = idx >= 0 ? { ...next[idx] } : { rowIndex };

    existing.expenseStoreCode = storeCode ?? undefined;
    existing.expenseStoreName = isCommon ? 'Chi phí chung' : storeName;
    existing.isCommonExpense = isCommon;
    // "Không gán" also clears skip
    if (!storeCode && !isCommon) {
      existing.skipOnImport = false;
    }

    if (idx >= 0) next[idx] = existing;
    else next.push(existing);

    onResolutionsChange(next);
    setExpenseRow(null);
  }, [resolutions, onResolutionsChange]);

  // ── Effective status (skip + resolve) ──────────────────────
  const getEffectiveStatus = useCallback((row: BankStatementDryRunRow): string => {
    const resolution = getResolution(row.rowIndex);
    if (resolution?.skipOnImport) return 'skipped';
    if (row.status === 'missing_customer' && resolution) return 'ok';
    return row.status;
  }, [getResolution]);

  const effectiveReadyCount = useMemo(
    () => dryRunResult.rows.filter(r => getEffectiveStatus(r) === 'ok').length,
    [dryRunResult.rows, getEffectiveStatus]
  );
  const effectiveMissingCount = useMemo(
    () => dryRunResult.rows.filter(r => getEffectiveStatus(r) === 'missing_customer').length,
    [dryRunResult.rows, getEffectiveStatus]
  );
  const effectiveErrorCount = useMemo(
    () => dryRunResult.rows.filter(r => getEffectiveStatus(r) === 'error').length,
    [dryRunResult.rows, getEffectiveStatus]
  );
  const effectiveSkipCount = useMemo(
    () => dryRunResult.rows.filter(r => getEffectiveStatus(r) === 'skipped').length,
    [dryRunResult.rows, getEffectiveStatus]
  );

  const hasMissingCustomers = effectiveMissingCount > 0;
  const allMissingResolved = !hasMissingCustomers;

  const unhandledMissingCount = useMemo(
    () => dryRunResult.rows.filter(r => {
      if (getEffectiveStatus(r) !== 'missing_customer') return false;
      const res = getResolution(r.rowIndex);
      return !res || !res.skipOnImport;
    }).length,
    [dryRunResult.rows, getEffectiveStatus, getResolution]
  );

  const filteredRows = useMemo(() => {
    let rows = filterStatus === 'all'
      ? dryRunResult.rows
      : dryRunResult.rows.filter(r => getEffectiveStatus(r) === filterStatus);

    if (showBatchDetailOnly) {
      rows = rows.filter(r => getBatchDetailLines(r).length > 0);
    }
    return rows;
  }, [dryRunResult.rows, filterStatus, getEffectiveStatus, showBatchDetailOnly, getBatchDetailLines]);

  const STATUS_FILTERS = useMemo(() => [
    { key: 'all', label: 'Tất cả', count: dryRunResult.totalRows },
    { key: 'ok', label: 'Sẵn sàng', count: effectiveReadyCount },
    { key: 'missing_customer', label: 'Thiếu KH', count: effectiveMissingCount },
    { key: 'error', label: 'Lỗi', count: effectiveErrorCount },
    { key: 'skipped', label: 'Bỏ qua', count: effectiveSkipCount },
  ], [dryRunResult.totalRows, effectiveReadyCount, effectiveMissingCount, effectiveErrorCount, effectiveSkipCount]);

  // ── Render batch detail modal ──────────────────────────────
  const renderBatchDetailModal = () => {
    if (!detailRow) return null;
    const lines = getBatchDetailLines(detailRow);
    if (lines.length === 0) return null;

    const totalDetail = lines.reduce((s, l) => s + l.amount, 0);
    return createPortal(
      <div className={styles.batchDetailOverlay} onClick={() => setDetailRow(null)}>
        <div className={styles.batchDetailModal} onClick={e => e.stopPropagation()}>
          <div className={styles.detailHeader}>
            <h3 className={styles.detailTitle}>Chi tiết sao kê lô — Dòng #{detailRow.rowIndex + 1}</h3>
            <button className={styles.detailClose} onClick={() => setDetailRow(null)}>✕</button>
          </div>
          <div className={styles.detailSummary}>
            <span>Số tiền giao dịch: <strong>{detailRow.amount?.toLocaleString('vi-VN')}₫</strong></span>
            <span>Số dòng chi tiết: <strong>{lines.length}</strong></span>
            <span>Tổng chi tiết: <strong>{totalDetail.toLocaleString('vi-VN')}₫</strong></span>
            <span style={{ color: Math.abs(totalDetail - (detailRow.amount || 0)) < 1000 ? '#16a34a' : '#d97706' }}>
              {Math.abs(totalDetail - (detailRow.amount || 0)) < 1000 ? '✅ Khớp' : '⚠️ Lệch'}
            </span>
          </div>
          <div className={styles.detailTableWrap}>
            <table className={styles.detailTable}>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Người thụ hưởng</th>
                  <th>Số TK</th>
                  <th>Ngân hàng</th>
                  <th>Số FT</th>
                  <th style={{ textAlign: 'right' }}>Số tiền</th>
                </tr>
              </thead>
              <tbody>
                {lines.map(l => (
                  <tr key={l.lineIndex}>
                    <td>{l.lineIndex + 1}</td>
                    <td>{l.beneficiaryName}</td>
                    <td style={{ fontFamily: 'monospace', fontSize: 12 }}>{l.accountNumber || ''}</td>
                    <td>{l.bankName || ''}</td>
                    <td style={{ fontFamily: 'monospace', fontSize: 12 }}>{l.ftNumber || ''}</td>
                    <td style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>{l.amount.toLocaleString('vi-VN')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>,
      document.body,
    );
  };

  return (
    <div className={styles.container}>
      <h2 className={styles.title}>Bước 2: Kết quả phân tích</h2>
      <p className={styles.subtitle}>
        Click vào dòng "Thiếu KH" để xử lý thông tin khách hàng.
        Click nút <strong>"Mã batch"</strong> để cấu hình mã tham chiếu cho giao dịch batch.
        Click <strong>"📄"</strong> để xem chi tiết lô thanh toán.
        Click <strong>"Bỏ qua"</strong> để skip dòng lỗi và chỉ import dữ liệu sẵn sàng.
      </p>

      {/* Summary cards */}
      <div className={styles.summaryRow}>
        <div className={styles.summaryCardGreen}>
          <div className={styles.summaryNumber}>{effectiveReadyCount}</div>
          <div className={styles.summaryLabel}>Sẵn sàng</div>
        </div>
        <div className={styles.summaryCardYellow}>
          <div className={styles.summaryNumber}>{effectiveMissingCount}</div>
          <div className={styles.summaryLabel}>Thiếu khách hàng</div>
        </div>
        <div className={styles.summaryCardRed}>
          <div className={styles.summaryNumber}>{effectiveErrorCount}</div>
          <div className={styles.summaryLabel}>Lỗi</div>
        </div>
        {effectiveSkipCount > 0 && (
          <div className={styles.summaryCardGreen} style={{ background: '#f3f4f6', borderColor: '#d1d5db' }}>
            <div className={styles.summaryNumber} style={{ color: '#9ca3af' }}>{effectiveSkipCount}</div>
            <div className={styles.summaryLabel} style={{ color: '#6b7280' }}>Bỏ qua</div>
          </div>
        )}
      </div>

      {/* Filter tabs */}
      <div className={styles.filterRow}>
        {STATUS_FILTERS.map(f => (
          <button
            key={f.key}
            className={`${styles.filterBtn} ${filterStatus === f.key ? styles.filterBtnActive : ''}`}
            onClick={() => setFilterStatus(f.key)}
          >
            {f.label} <span className={styles.filterCount}>({f.count})</span>
          </button>
        ))}
        <label className={styles.batchDetailCheckbox} title="Chỉ hiển thị giao dịch có lô chi tiết">
          <input
            type="checkbox"
            checked={showBatchDetailOnly}
            onChange={e => setShowBatchDetailOnly(e.target.checked)}
          />
          <span>Có lô chi tiết</span>
        </label>
      </div>

      {/* Grid table */}
      <div className={styles.tableWrap}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th className={styles.th}>#</th>
              <th className={styles.th}>Loại</th>
              <th className={styles.thRight}>Số tiền</th>
              <th className={styles.th}>Đối tượng</th>
              <th className={styles.th}>Nội dung</th>
              <th className={styles.th}>Chứng từ gốc</th>
              <th className={styles.th}>Mã batch</th>
              <th className={styles.th}>Cửa hàng</th>
              <th className={styles.th}>Thao tác</th>
              <th className={styles.th}>Trạng thái</th>
            </tr>
          </thead>
          <tbody>
            {filteredRows.map((row) => {
              const resolution = getResolution(row.rowIndex);
              const effectiveStatus = getEffectiveStatus(row);
              const isResolved = resolution !== undefined;
              const isMissing = row.status === 'missing_customer';
              const isClickable = isMissing && !isResolved;
              const isSkipped = resolution?.skipOnImport;
              const voucherLabel = row.voucherType === 'bao_co' ? 'BC'
                : row.voucherType === 'bao_no' ? 'BN'
                : row.voucherType === 'unc' ? 'UNC'
                : row.voucherType === 'ctnb' ? 'CTNB'
                : row.voucherType || '';

              const hasBatchRefs = (row.detectedBatchRefs?.length ?? 0) > 0;
              const batchResolution = resolution?.selectedBatchRef;
              const hasBatchDetail = row.hasBatchDetail;
              const isBatchTx = resolution?.selectedBatchRef !== undefined;

              const detailLines = getBatchDetailLines(row);
              const hasDetailLines = detailLines.length > 0;
              const hasExpenseStore = resolution?.expenseStoreCode || resolution?.isCommonExpense;

              return (
                <tr
                  key={row.rowIndex}
                  className={`${styles.tr} ${isClickable ? styles.trClickable : ''} ${effectiveStatus === 'ok' && isResolved ? styles.trResolved : ''} ${row.status === 'error' || isSkipped ? styles.trError : ''}`}
                  onClick={() => isClickable && setResolveRow(row)}
                  title={isClickable ? 'Click để xử lý khách hàng' : undefined}
                >
                  <td className={styles.td}>{row.rowIndex + 1}</td>
                  <td className={styles.td}>{voucherLabel}</td>
                  <td className={styles.tdRight}>
                    {row.amount !== undefined && row.amount !== null
                      ? row.amount.toLocaleString('vi-VN')
                      : ''}
                  </td>
                  <td className={styles.td}>
                    {isResolved && !isSkipped ? (
                      <span className={styles.resolvedBadge}>
                        ✅ {resolution.existingCustomerId ? 'Đã chọn' : 'Sẽ tạo mới'}
                      </span>
                    ) : isMissing && !isSkipped ? (
                      <span className={styles.missingLink}>⛔ Chưa có — Click</span>
                    ) : isSkipped ? (
                      <span className={styles.skipBadge}>⏭ Bỏ qua</span>
                    ) : (
                      row.matchedCustomerName || row.counterpartyName || ''
                    )}
                  </td>
                  <td className={styles.td} title={row.description || ''}>
                    {row.description ? (
                      row.description.length > 35 ? row.description.slice(0, 35) + '…' : row.description
                    ) : ''}
                  </td>
                  <td className={styles.td} title={row.importReference || ''}>
                    {row.importReference ? (
                      <span className={styles.importRefText}>
                        {row.importReference.length > 30 ? row.importReference.slice(0, 30) + '…' : row.importReference}
                      </span>
                    ) : ''}
                  </td>
                  <td className={styles.td}>
                    {hasBatchRefs ? (
                      <div className={styles.batchRefCell}>
                        <button
                          className={styles.batchRefBtn}
                          onClick={(e) => {
                            e.stopPropagation();
                            setBatchRefRow({
                              row,
                              currentSelectedRef: batchResolution,
                              currentIsBatch: isBatchTx,
                              currentReason: resolution?.batchConfirmReason,
                            });
                          }}
                        >
                          {batchResolution ? (
                            <span className={styles.batchRefSet}>
                              📋 {batchResolution.length > 12 ? batchResolution.slice(0, 12) + '…' : batchResolution}
                            </span>
                          ) : (
                            <span className={styles.batchRefLink}>
                              🏷️ ({row.detectedBatchRefs!.length})
                            </span>
                          )}
                        </button>
                        {/* Master-detail icon: click to show batch detail lines */}
                        {hasDetailLines && (
                          <span
                            className={styles.hasDetailHint}
                            style={{ cursor: 'pointer' }}
                            onClick={(e) => {
                              e.stopPropagation();
                              setDetailRow(row);
                            }}
                            title="Xem chi tiết lô thanh toán"
                          >
                            📄
                          </span>
                        )}
                        {hasBatchDetail && !hasDetailLines && (
                          <span className={styles.hasDetailHint}>📄</span>
                        )}
                        {!hasBatchDetail && batchResolution && (
                          <span className={styles.noDetailHint}>⚠️</span>
                        )}
                      </div>
                    ) : (
                      <span className={styles.noBatchRef}>—</span>
                    )}
                  </td>
                  <td className={styles.td}>
                    {hasExpenseStore ? (
                      <span className={styles.expenseBtnSet} title="Click để đổi">
                        {resolution?.isCommonExpense ? '🏢 Chi phí chung' : `🏪 ${resolution?.expenseStoreCode}`}
                      </span>
                    ) : (
                      <span style={{ color: '#d1d5db', fontSize: 12 }}>—</span>
                    )}
                  </td>
                  <td className={styles.td}>
                    <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                      <button
                        className={`${styles.skipBtn} ${isSkipped ? styles.skipBtnActive : ''}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          handleToggleSkip(row.rowIndex);
                        }}
                        title={isSkipped ? 'Bỏ bỏ qua' : 'Bỏ qua dòng này'}
                      >
                        {isSkipped ? '✅ Đã bỏ qua' : '⏭ Bỏ qua'}
                      </button>
                      <button
                        className={`${styles.expenseBtn} ${hasExpenseStore ? styles.expenseBtnSet : ''}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          setExpenseRow(row);
                        }}
                        title="Gán chi phí cho cửa hàng/chung"
                      >
                        💰 CP
                      </button>
                    </div>
                  </td>
                  <td className={styles.td}>
                    {isSkipped ? (
                      <span className={styles.skipBadge}>⏭ Bỏ qua</span>
                    ) : (
                      <span className={`${styles.statusBadge} ${styles[STATUS_LABEL[effectiveStatus]?.className || '']}`}>
                        {STATUS_LABEL[effectiveStatus]?.text || effectiveStatus}
                      </span>
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Actions */}
      <div className={styles.actions}>
        <button onClick={onBack} className={styles.secondaryBtn}>
          ← Quay lại
        </button>
        <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
          {effectiveSkipCount > 0 && (
            <span style={{ fontSize: 13, color: '#6b7280' }}>
              🗑️ Bỏ qua {effectiveSkipCount} dòng — sẽ không import
            </span>
          )}
          <button
            onClick={onNext}
            disabled={hasMissingCustomers && !allMissingResolved}
            className={styles.primaryBtn}
          >
            {unhandledMissingCount > 0
              ? `Còn ${unhandledMissingCount} KH chưa xử lý`
              : `Tiếp theo: Xác nhận & Import → (${effectiveReadyCount} dòng)`}
          </button>
        </div>
      </div>

      {/* Modals */}
      {resolveRow && (
        <CustomerResolveModal
          rowIndex={resolveRow.rowIndex}
          counterpartyName={resolveRow.counterpartyName || resolveRow.matchedCustomerName || ''}
          amount={resolveRow.amount}
          description={resolveRow.description}
          existingResolution={getResolution(resolveRow.rowIndex)}
          onSave={handleResolveSave}
          onClose={() => setResolveRow(null)}
        />
      )}

      {batchRefRow && (
        <BatchRefConfigModal
          row={batchRefRow.row}
          currentSelectedRef={batchRefRow.currentSelectedRef}
          currentIsBatch={batchRefRow.currentIsBatch}
          currentReason={batchRefRow.currentReason}
          onSave={(selectedBatchRef, isBatchTransaction, reason) =>
            handleBatchRefSave(batchRefRow.row.rowIndex, selectedBatchRef, isBatchTransaction, reason)
          }
          onClose={() => setBatchRefRow(null)}
        />
      )}

      {renderBatchDetailModal()}
      {expenseRow && (
        <ExpenseAssignmentModal
          expenseRow={expenseRow}
          currentResolution={getResolution(expenseRow.rowIndex)}
          onSave={handleExpenseSave}
          onClose={() => setExpenseRow(null)}
        />
      )}
    </div>
  );
};

export default Step2DryRun;
